import{_ as t,a as r,b as s,c as l,d as e,e as i,f as a,g as n}from"./chunks/step7.Byy3MQ1i.js";import{_ as g,o as c,c as p,af as d}from"./chunks/framework.5D6DWnkB.js";const x=JSON.parse('{"title":"飞书机器人注册与配置全通关指南（图文保姆级）","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/feishu-bot-setup.md","filePath":"tutorials/feishu-bot-setup.md"}'),h={name:"tutorials/feishu-bot-setup.md"};function m(_,o,u,f,b,k){return c(),p("div",null,[...o[0]||(o[0]=[d('<h1 id="飞书机器人注册与配置全通关指南-图文保姆级" tabindex="-1">飞书机器人注册与配置全通关指南（图文保姆级） <a class="header-anchor" href="#飞书机器人注册与配置全通关指南-图文保姆级" aria-label="Permalink to &quot;飞书机器人注册与配置全通关指南（图文保姆级）&quot;">​</a></h1><p>这份指南将手把手、图文并茂地教你如何从零开始配置一个专属的机器人。全程免费，不需要你懂代码，也不需要公网 IP！</p><hr><h3 id="第一步-注册飞书与创建企业" tabindex="-1">第一步：注册飞书与创建企业 <a class="header-anchor" href="#第一步-注册飞书与创建企业" aria-label="Permalink to &quot;第一步：注册飞书与创建企业&quot;">​</a></h3><ol><li><strong>打开官网</strong>：首先在浏览器打开 <a href="https://www.feishu.cn/" target="_blank" rel="noreferrer">飞书官网</a>。</li><li><strong>手机号登录</strong>：点击右上角的“登录”，直接用你的手机号接收验证码登录。</li><li><strong>创建企业</strong>：登录后，选择 <strong>“创建企业”</strong>（企业名称随便填，基础版永久免费）。</li></ol><hr><h3 id="第二步-在开放平台创建你的-机器人应用" tabindex="-1">第二步：在开放平台创建你的“机器人应用” <a class="header-anchor" href="#第二步-在开放平台创建你的-机器人应用" aria-label="Permalink to &quot;第二步：在开放平台创建你的“机器人应用”&quot;">​</a></h3><ol><li><strong>进入开发者后台</strong>：在浏览器打开 <a href="https://open.feishu.cn/app" target="_blank" rel="noreferrer">飞书开放平台 (open.feishu.cn/app)</a>。</li><li><strong>创建自建应用</strong>：点击 <strong>「创建企业自建应用」</strong> 这个大按钮。</li><li><strong>填写应用信息</strong>：填好应用名称和描述，上传头像，点击 <strong>「创建」</strong>。</li></ol><hr><h3 id="第三步-给应用添加-机器人-灵魂" tabindex="-1">第三步：给应用添加“机器人”灵魂 <a class="header-anchor" href="#第三步-给应用添加-机器人-灵魂" aria-label="Permalink to &quot;第三步：给应用添加“机器人”灵魂&quot;">​</a></h3><p>刚创建好的应用只是个名字，我们需要赋予它作为“聊天机器人”的能力，它才能在飞书里出现。</p><ol><li>在应用的管理后台，看左侧菜单栏，找到并点击 <strong>「添加应用能力」</strong>。</li><li>在右侧出现的卡片列表中，找到 <strong>「机器人」</strong>，然后点击它下面的 <strong>「添加」</strong> 按钮。</li></ol><p><img src="'+t+'" alt="添加机器人能力"></p><ol start="3"><li>添加完成后，左侧菜单会多出一个 <strong>「机器人」</strong> 的子选项。点击它，你就会看到机器人的专属配置面板，并且上方会提示你需要去开通权限。</li></ol><p><img src="'+r+'" alt="机器人配置面板"></p><hr><h3 id="第四步-配置核心权限-🔥极易踩坑-必看" tabindex="-1">第四步：配置核心权限（🔥极易踩坑，必看！） <a class="header-anchor" href="#第四步-配置核心权限-🔥极易踩坑-必看" aria-label="Permalink to &quot;第四步：配置核心权限（🔥极易踩坑，必看！）&quot;">​</a></h3><p>机器人要能看懂你发的消息、能给你发图片，必须要有相应的“权限”。</p><ol><li>看左侧菜单栏，点击 <strong>「权限管理」</strong>。</li><li>此时你可以通过点击中间的 <strong>「开通权限」</strong> 按钮，唤出右侧的权限搜索抽屉。</li></ol><p><img src="'+s+'" alt="开通权限总览"></p><ol start="3"><li><p><strong>【核心避坑】</strong>：在右侧抽屉的右上角搜索框里，依次搜索以下英文代码，并在下方出现的选项中<strong>打上勾</strong>。对于日常手机聊天、群组互动，<strong>以下是核心必开权限（缺一不可）</strong>：</p><p><strong>【核心聊天能力】</strong></p><ul><li>🔍 <code>im:message:send_as_bot</code>（获取单聊、群组消息 —— <strong>最重要，必须开！</strong>）</li><li>🔍 <code>im:message.p2p_msg:readonly</code>（接收单聊消息）</li><li>🔍 <code>im:message.group_at_msg:readonly</code>（接收群聊中@我的消息）</li><li>🔍 <code>im:message:readonly</code>（获取消息内容）</li><li>🔍 <code>im:message</code>（获取和发送单聊、群组消息）</li><li>🔍 <code>im:resource</code>（获取消息中的图片、文件）</li></ul><p><strong>【可选：如果你需要在群里拉它】</strong></p><ul><li>🔍 <code>im:chat</code>（获取和更新群组信息）</li><li>🔍 <code>im:chat:read</code>（读取群组信息）</li></ul></li></ol><p><img src="'+l+'" alt="搜索并添加权限"></p><p>⚠️ <strong>【史诗级巨坑警告】</strong>：在飞书后台，你在这里勾选的权限只是<strong>暂存状态</strong>！如果不进行第六步的“发布新版本”，新权限永远不会生效！</p><hr><h3 id="第五步-开启-websocket-长连接-小白免公网-ip-秘籍" tabindex="-1">第五步：开启 WebSocket 长连接（小白免公网 IP 秘籍） <a class="header-anchor" href="#第五步-开启-websocket-长连接-小白免公网-ip-秘籍" aria-label="Permalink to &quot;第五步：开启 WebSocket 长连接（小白免公网 IP 秘籍）&quot;">​</a></h3><p>为了让机器人能秒回你的消息，并且<strong>完全不需要你去搞复杂的公网 IP 和内网穿透</strong>，我们需要开启飞书的 WebSocket 模式。</p><ol><li>看左侧菜单栏，找到并点击 <strong>「事件与回调」</strong>。</li><li>在右侧的“事件配置”页面中，点击“订阅方式”旁边的小铅笔图标，<strong>将其修改为：「长连接（推荐）」</strong>。 <em>正如官方提示：只要选了这个，你的局域网旧电脑或虚拟机就能直接秒收消息！</em></li></ol><p><img src="'+e+'" alt="切换为长连接"></p><ol start="3"><li>模式切换好后，向下滚动页面，点击蓝色的 <strong>「添加事件」</strong> 按钮。</li><li>在弹出的搜索框里，搜索并勾选你要让机器人监听的事件。 <ul><li><strong>必选核心事件：</strong> 搜索 <code>im.message.receive_v1</code>（中文名叫：接收消息 v1.0）。<strong>只有勾了这个，机器人才知道你说话了。</strong></li><li>其他群组相关的事件可以按需添加。</li></ul></li></ol><p><img src="'+i+'" alt="添加接收消息事件"></p><hr><h3 id="第六步-发布应用-让所有配置真正生效" tabindex="-1">第六步：发布应用（让所有配置真正生效！） <a class="header-anchor" href="#第六步-发布应用-让所有配置真正生效" aria-label="Permalink to &quot;第六步：发布应用（让所有配置真正生效！）&quot;">​</a></h3><p><strong>⚠️ 再次警告：你刚才勾选的任何权限、配置的任何长连接，如果不发布新版本，统统是废纸！</strong></p><ol><li>看左侧菜单栏，一直向下滚，找到 <strong>「应用发布」</strong> 下的 <strong>「版本管理与发布」</strong>。</li><li>点击页面右上角大大的蓝色 <strong>「创建版本」</strong> 按钮。</li></ol><p><img src="'+a+'" alt="创建版本并发布"></p><ol start="3"><li><strong>应用版本号</strong>：随便填（如 <code>1.0.0</code> 或递增 <code>1.0.1</code>）。</li><li><strong>更新说明</strong>：随便填（如“更新基础聊天权限”）。</li><li><strong>可用范围</strong>：选择你自己，或直接选“全部成员”。</li><li>点击最下方的 <strong>「保存并申请发布」</strong>。</li><li>因为你是超级管理员，系统会直接提示审核通过。<strong>至此，你配的所有权限才真正刻进机器人的灵魂里！</strong></li></ol><hr><h3 id="第七步-拿到机器人的-身份证-并启动配置" tabindex="-1">第七步：拿到机器人的“身份证”并启动配置 <a class="header-anchor" href="#第七步-拿到机器人的-身份证-并启动配置" aria-label="Permalink to &quot;第七步：拿到机器人的“身份证”并启动配置&quot;">​</a></h3><p>当你完成上一步的版本发布后，你的机器人已经是一个健全的灵魂了！现在我们只需要拿到它的“身份证”和“密码”。</p><ol><li>看左侧菜单栏，回到最上面的 <strong>「凭证与基础信息」</strong>。</li><li>此时页面顶部应该会显示绿色的“当前修改均已发布”。在页面中间的“应用凭证”区域，你会看到两个核心信息： <ul><li><strong>App ID</strong> (机器人的账号，一般是 <code>cli_</code> 开头)</li><li><strong>App Secret</strong> (机器人的密码，点击旁边的小眼睛可以显示出来)</li></ul></li></ol><p><img src="'+n+'" alt="获取应用凭证"></p><ol start="3"><li>点击旁边的小图标，把这两串字符复制下来。</li><li>将它们填入到你的 AI 框架（如 OpenClaw）对应的 <code>feishu</code> 配置文件中即可。</li></ol>',42)])])}const S=g(h,[["render",m]]);export{x as __pageData,S as default};
